namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    // Splits text into sentences on ., !, or ? followed by whitespace or end-of-string.
    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","in","on","at","to","for",
        "of","with","by","from","as","into","about","between","through","after",
        "above","below","it","its","this","that","these","those","i","you","he",
        "she","we","they","me","him","her","us","them","my","your","his","our",
        "their","not","no","so","if","then","than","too","very","just"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        var sentences = SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scoredSentences = sentences
            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => sentences[s.Index]);

        return string.Join(" ", scoredSentences);
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = GetWords(sentence);
        if (words.Length == 0)
            return 0;

        double score = 0;
        foreach (var word in words)
        {
            if (wordFrequencies.TryGetValue(word, out var freq))
                score += freq;
        }
        return score / words.Length;
    }

    private static string[] GetWords(string text) =>
        text.Split([' ', '\t', '\n', '\r', ',', ';', ':', '"', '\'', '(', ')', '[', ']'],
            StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText must not be empty.");

        if (request.MaxSentences < 1)
            return BadRequest("MaxSentences must be at least 1.");

        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);
        var originalWords = request.DocumentText.Split(' ', StringSplitOptions.RemoveEmptyEntries).Length;
        var summaryWords = summary.Split(' ', StringSplitOptions.RemoveEmptyEntries).Length;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = originalWords,
            SummaryWordCount = summaryWords
        });
    }
}

